function solve(nums) {
    const MAX_VAL = 100000;
    // We need a slightly larger limit to ensure we find the next prime/non-prime
    const SIEVE_LIMIT = MAX_VAL + 100; 

    // 1. Sieve of Eratosthenes to precalculate primes
    const isPrime = new Array(SIEVE_LIMIT + 1).fill(true);
    isPrime[0] = isPrime[1] = false;

    for (let p = 2; p * p <= SIEVE_LIMIT; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i <= SIEVE_LIMIT; i += p)
                isPrime[i] = false;
        }
    }

    let totalOperations = 0;
    const N = nums.length;

    for (let i = 0; i < N; i++) {
        const currentNum = nums[i];
        let cost = 0;

        if (i % 2 === 0) {
            // Even index: Must be PRIME
            let target = Math.max(currentNum, 2); // Minimum prime is 2

            // Find the smallest prime >= currentNum
            while (target <= SIEVE_LIMIT && !isPrime[target]) {
                target++;
            }

            if (target > SIEVE_LIMIT) {
                // This case should theoretically not happen given the problem constraints 
                // and SIEVE_LIMIT choice, but serves as a safeguard.
                // If it happens, we would need a more dynamic prime finding algorithm.
                // For competitive programming context, we assume SIEVE_LIMIT is sufficient.
            }

            cost = target - currentNum;

        } else {
            // Odd index: Must be NON-PRIME
            let target = currentNum;

            // Find the smallest non-prime >= currentNum
            while (true) {
                // 1 is non-prime by definition (not > 1 and only divisible by 1 and itself)
                if (target === 1) {
                    // 1 is non-prime
                    break; 
                }

                // Check primality using the sieve. If it's not prime, it's non-prime (composite).
                // We must ensure target is within sieve bounds, though target grows slowly.
                if (target <= SIEVE_LIMIT && !isPrime[target]) {
                    break; // Found a non-prime (composite or 1, handled above)
                }

                // If we reached here, target is prime, so increment and check next
                target++;
            }

            cost = target - currentNum;
        }

        totalOperations += cost;
    }

    return totalOperations;
}

