public class Solution {

    /**
     * Returns the minimum number of operations to make nums an alternating prime array.
     * Even index -> Prime, Odd index -> Non-Prime.
     * Operations: Incrementing any element by 1.
     */
    public static long solve(long[] nums) {
        // Constraints: nums[i] <= 10^5. We need a buffer for finding next primes/non-primes.
        final int MAX_VAL = 100000;
        // A safe limit: Max gap near 10^5 is small (14). 150 buffer is extremely safe.
        final int SIEVE_LIMIT = MAX_VAL + 150; 

        // 1. Sieve of Eratosthenes to precalculate primes
        boolean[] isPrime = new boolean[SIEVE_LIMIT + 1];
        Arrays.fill(isPrime, true);
        if (SIEVE_LIMIT >= 0) isPrime[0] = false;
        if (SIEVE_LIMIT >= 1) isPrime[1] = false;

        for (int p = 2; p * p <= SIEVE_LIMIT; p++) {
            if (isPrime[p]) {
                for (int i = p * p; i <= SIEVE_LIMIT; i += p)
                    isPrime[i] = false;
            }
        }

        long totalOperations = 0;
        int N = nums.length;

